await new Promise(r => setTimeout(r, 500));
return [{
  json: {
    status: 'trained',
    model_version: '1.0.0',
    trained_at: new Date().toISOString(),
    samples_used: 142
  }
}];

// Date du jour au format ISO (YYYY-MM-DD), utilisée par les 2 branches suivantes
const today = new Date().toISOString().split('T')[0];
return [{
  json: {
    date: today
  }
}];

// Cette node reçoit le statut HTTP brut de "Vérifier Jour Férié"
// 200 = jour férié, 204 = jour normal
const statusCode = $input.first().json.statusCode;
const type_jour = statusCode === 200 ? 'ferie' : 'normal';

return [{
  json: {
    type_jour: type_jour
  }
}];

const items = $input.all();
const merged = Object.assign({}, ...items.map(i => i.json));

const date = $('Date du Jour').first().json.date;

// Open-Meteo retourne: current.temperature_2m et current.wind_speed_10m
const currentWeather = merged.current || {};
const temperature = currentWeather.temperature_2m ?? merged.temperature ?? 'N/A';
const wind_speed  = currentWeather.wind_speed_10m  ?? merged.wind_speed  ?? 'N/A';
const type_jour   = merged.type_jour ?? 'normal';

return [{
  json: {
    date,
    temperature,
    wind_speed,
    type_jour
  }
}];

const predictions = $input.first().json.predictions;

// Totaux par heure
const byHour = {};
for (const p of predictions) {
  if (!byHour[p.hour]) byHour[p.hour] = 0;
  byHour[p.hour] += p.total_visits;
}

// Heure de pointe
const heurePointe = Object.entries(byHour)
  .sort((a, b) => b[1] - a[1])[0];

// Total journalier
const totalJour = Object.values(byHour).reduce((a, b) => a + b, 0);

// Profils détaillés (uniquement > 0, agrégés toutes caméras)
const profileCount = {};
for (const p of predictions) {
  for (const prof of p.profile) {
    if (prof.visits_predicted > 0) {
      const key = `${prof.gender}_${prof.age}`;
      profileCount[key] = (profileCount[key] || 0) + prof.visits_predicted;
    }
  }
}

// Trier par volume décroissant
const profilesSorted = Object.entries(profileCount)
  .sort((a, b) => b[1] - a[1])
  .map(([key, count]) => {
    const [gender, age] = key.split('_');
    return { gender, age, visits: count };
  });

const profilDominant = profilesSorted[0] 
  ? `${profilesSorted[0].gender} ${profilesSorted[0].age}` 
  : 'N/A';

// Détail par heure avec profils actifs
const detailParHeure = {};
for (const p of predictions) {
  const h = p.hour;
  if (!detailParHeure[h]) {
    detailParHeure[h] = { total: 0, cameras: {}, profils_actifs: {} };
  }
  detailParHeure[h].total += p.total_visits;

  // Par caméra
  detailParHeure[h].cameras[p.camera] = p.total_visits;

  // Profils actifs cette heure
  for (const prof of p.profile) {
    if (prof.visits_predicted > 0) {
      const key = `${prof.gender} ${prof.age}`;
      detailParHeure[h].profils_actifs[key] = 
        (detailParHeure[h].profils_actifs[key] || 0) + prof.visits_predicted;
    }
  }
}

return [{
  json: {
    date: predictions[0]?.date || new Date().toISOString().split('T')[0],
    visiteurs_prevus_total: totalJour,
    heure_pointe: `${heurePointe[0]}h00`,
    visiteurs_heure_pointe: heurePointe[1],
    profil_dominant: profilDominant,
    profils_par_volume: profilesSorted,
    detail_par_heure: detailParHeure
  }
}];

const data = $input.first().json;
const ctx = $('Préparer Contexte Jour').first().json;

const temperature = data.temperature ?? ctx.temperature ?? 'N/A';
const wind_speed  = data.wind_speed  ?? ctx.wind_speed  ?? 'N/A';
const type_jour   = data.type_jour   ?? ctx.type_jour   ?? 'normal';
const date        = data.date        ?? ctx.date;

const jourLabel = type_jour === 'ferie' ? 'jour férié' : 'jour ouvrable';
const meteo     = `${temperature}°C, vent ${wind_speed} km/h`;

// Top 3 profils les plus représentés (déjà triés par volume décroissant)
const profilesStr = (data.profils_par_volume || [])
  .slice(0, 3)
  .map(p => `${p.gender} ${p.age} (${p.visits} visites)`)
  .join(', ');

// Top 3 créneaux horaires les plus fréquentés, à partir du détail réel
// par heure (et non uniquement l'heure de pointe unique), pour identifier
// une vraie plage de rush comme dans le rapport de référence.
const detail = data.detail_par_heure || {};
const topHeures = Object.entries(detail)
  .map(([h, v]) => ({ heure: Number(h), total: v.total }))
  .sort((a, b) => b.total - a.total)
  .slice(0, 3);

const rushStr = topHeures
  .map(h => `${h.heure}h-${h.heure + 1}h (${h.total} visiteurs)`)
  .join(', ');

// Part du total concentrée sur ces 3 créneaux, pour quantifier le rush
const totalJour   = data.visiteurs_prevus_total || 0;
const totalRush   = topHeures.reduce((acc, h) => acc + h.total, 0);
const partRushPct = totalJour > 0 ? Math.round((totalRush / totalJour) * 100) : 0;

const prompt = `Tu es l'assistant analytique de ShopAnalytics pour Anavid Store 360.
Tu rédiges une notification quotidienne envoyée à l'équipe du magasin, basée UNIQUEMENT sur les prédictions ML ci-dessous. N'invente aucun chiffre absent de ces données.

Contexte du ${date} :
- Météo prévue : ${meteo}
- Type de jour : ${jourLabel}

Prédictions ML :
- Total visiteurs prévu sur la journée : ${data.visiteurs_prevus_total}
- Heure de pointe (créneau le plus chargé) : ${data.heure_pointe} avec ${data.visiteurs_heure_pointe} visiteurs
- Principaux créneaux de rush : ${rushStr} — soit environ ${partRushPct}% du trafic total de la journée
- Profil dominant : ${data.profil_dominant}
- Principaux profils visiteurs attendus : ${profilesStr}

Rédige un message professionnel, concis (5 à 7 phrases) et structuré en français, à destination de l'équipe du magasin, qui reprend fidèlement ces données :
1. Indique la météo et si c'est un jour férié ou ouvrable.
2. Annonce le nombre total de visiteurs attendus dans la journée.
3. Précise les créneaux de rush identifiés (heures + part du trafic).
4. Mentionne le profil de clientèle dominant attendu.
5. Termine par 1 à 2 recommandations concrètes et actionnables sur le staffing, l'ouverture des caisses ou l'organisation des rayons pendant les créneaux de rush identifiés.

N'utilise pas de tableau ni de listes à puces : le message doit être un texte fluide adapté à une notification push.`;

return [{
  json: {
    prompt: prompt,
    prediction: {
      ...data,
      temperature,
      wind_speed,
      type_jour,
      date,
      top_heures_rush: topHeures,
      part_rush_pct: partRushPct,
    }
  }
}];

const llmText = $input.first().json.text?.trim();
const pred = $('Préparer Prompt Ollama').first().json.prediction;

const total = pred.visiteurs_prevus_total;
let niveau_affluence;
if (total < 50)       niveau_affluence = "Faible";
else if (total < 150) niveau_affluence = "Modéré";
else if (total < 350) niveau_affluence = "Élevé";
else                  niveau_affluence = "Très élevé";

return [{
  json: {
    type: 'llm_report',
    date: pred.date,
    generated_at: new Date().toISOString(),
    message: llmText,
    prediction: {
      visiteurs_prevus:       pred.visiteurs_prevus_total,
      profil_dominant:        pred.profil_dominant,
      niveau_affluence:       niveau_affluence,
      heure_pointe:           pred.heure_pointe,
      visiteurs_heure_pointe: pred.visiteurs_heure_pointe,
      profils_par_volume:     pred.profils_par_volume,
      detail_par_heure:       pred.detail_par_heure
    }
  }
}];

// Appel HTTP via $http natif de N8N (fetch et http sont bloqués)
const llmText = $input.first().json.text?.trim();
const prediction = $('Préparer Prompt Ollama').first().json.prediction;

let chatAnswer = llmText;

try {
  const response = await $http.request({
    method: 'POST',
    url: 'http://shopanalytics-django-api:8000/api/chat/',
    headers: { 'Content-Type': 'application/json' },
    body: {
      question: `Rapport quotidien automatique du ${prediction.date_prevision} : ${llmText}`
    },
    json: true
  });
  chatAnswer = response.answer || llmText;
} catch (err) {
  console.log('Django indisponible, fallback LLM : ' + err.message);
}

const notification = {
  id: Date.now(),
  date: prediction.date_prevision,
  generated_at: new Date().toISOString(),
  visiteurs_prevus: prediction.visiteurs_prevus,
  profil_dominant: prediction.profil_dominant,
  niveau_affluence: prediction.niveau_affluence,
  heure_pointe: `${prediction.heure_pointe_debut} - ${prediction.heure_pointe_fin}`,
  message: chatAnswer,
  model: 'llama3.2:3b-instruct-q4_K_M',
  type: 'daily_report'
};

return [{ json: notification }];

